customColumn1.onClick:
{{
  (async () => {
    const row = SearchResultTable.selectedRow;

    // 1. Insert sale item first
    const saleItem = await InsertSaleItem.run({
      asset_id: row.asset_id,
      sell_price: row.sell_price
    });

    const sale_item_id = saleItem[0].sale_item_id;

    // 2. Get platform fee %
    await GetPlatformFee.run();
    const pct = Number(GetPlatformFee.data?.[0]?.fee_percentage || 0);

    // 3. Calculate fee
    const fee = Number(row.sell_price) * (pct / 100);

    // 4. Insert fee into DB
    await InsertSaleFee.run({
      sale_item_id: sale_item_id,
      fee_type: SalePlatformSelect.selectedOptionValue + " Platform Fee",
      fee_amount: fee
    });

    // 5. Add item to saleList (UI only)
    storeValue(
      "saleList",
      (appsmith.store.saleList || []).concat({
        sale_item_id: sale_item_id,
        asset_id: row.asset_id,
        asset_ref: row.asset_ref,
        item_type: row.item_type,
        make: row.make,
        model: row.model,
        serial_number: row.serial_number,
        sell_price: row.sell_price,
        platform_fee: fee
      })
    );

    showAlert("Item added with platform fee applied", "success");
  })()
}}
